//! Dev tool: dump every extracted topology (nodes + properties) for a
//! source file, plus the gg-embed admission verdict per export.
//!
//! `cargo run --example dump_topology -- <file> [export]`

use std::fs;

use gnosis_polyglot::aot_gg_embed::supports_gg_embed_for_export;

fn main() {
    let mut args = std::env::args().skip(1);
    let path = args.next().expect("usage: dump_topology <file> [export]");
    let only = args.next();
    let source = fs::read_to_string(&path).expect("read source");
    let scan = gnosis_polyglot::parse_and_extract_orchestration(&source, &path)
        .expect("orchestration scan");
    for topology in &scan.scan_result.topologies {
        if let Some(name) = &only {
            if &topology.function_name != name {
                continue;
            }
        }
        println!("== export: {} ==", topology.function_name);
        println!(
            "   gg-embed supports: {}",
            supports_gg_embed_for_export(&scan, &topology.function_name)
        );
        for node in &topology.topology.nodes {
            println!("  node {} labels={:?}", node.id, node.labels);
            for (key, value) in &node.properties {
                if matches!(
                    key.as_str(),
                    "expr" | "callee" | "args" | "bind" | "param_names" | "name"
                ) {
                    println!("    {key} = {value}");
                }
            }
        }
        for edge in &topology.topology.edges {
            println!(
                "  edge {:?} -[{:?}]-> {:?}",
                edge.source_ids, edge.edge_type, edge.target_ids
            );
        }
    }
}
